B.M9=new A.aL("intro_accept_a",'Accept "a"','Build an automaton that accepts exactly the string "a" and rejects everything else.\nThis is your starting point \u2014 all other levels unlock from here.',"      n0 = A\n      n1 = B\n      n0 = (484.0, 380.0)\n      n1 = (784.0, 380.0)\n      n1 is accepted\n      n0 to n1 = a\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.YP,B.XW,0.5,"intro",!1,B.H,null,B.L,"",!1)
B.XJ=new A.c9("intro_accept_a")
B.a5p=new A.iy(5,"dfaVsNfa")
B.a5I=new A.dw("Two Kinds of Automaton","Levels in this game are tagged **DFA** or **NFA** (or neither, for bosses).\n\n\u2022 A **DFA** (Deterministic Finite Automaton) must have exactly one transition per symbol per state.\n\u2022 An **NFA** (Nondeterministic Finite Automaton) can have zero, one, or many transitions for the same symbol.",B.a5p)
B.a5P=new A.dw("DFA Rules","For a valid DFA over alphabet {a, b}:\n\n1. Every state must have **exactly one** outgoing transition for each symbol.\n2. No \u03b5 (epsilon / free-jump) transitions are allowed.\n3. There must be exactly **one start state**.\n\nIf your submission violates any of these, the checker will tell you exactly which states are the problem.",B.bD)
B.a5J=new A.dw("NFA Rules","An NFA is more flexible \u2014 it **may** have:\n\n\u2022 Multiple outgoing arrows for the **same** symbol from one state\n\u2022 **\u03b5-transitions** (free jumps, drawn as arrows with no label)\n\u2022 States with **no** outgoing arrow for some symbol\n\nAn NFA accepts a string if **any** path through the machine leads to an accept state.",B.bD)
B.a5L=new A.dw('The "." (dot) Symbol','A transition labelled **"."** matches **any single symbol** from the alphabet.\n\nThis is a shorthand that saves you drawing one arrow per symbol. For example, a self-loop "." on a state means "stay here for any symbol".',B.bD)
B.a5q=new A.iy(6,"epsilonTransition")
B.a5D=new A.dw("Epsilon (\u03b5) Transitions","An **\u03b5-transition** (drawn without a label) is a free jump \u2014 the machine moves to the next state without consuming any input.\n\nIn the canvas, draw an arrow between two states and **clear the label** to create an \u03b5-transition. Only NFAs may use these.",B.a5q)
B.PB=s([B.a5I,B.a5P,B.a5J,B.a5L,B.a5D],t.nY)
