B.MK=new A.aL("dsl_binary_mod8","Binary Mod 8","Build a DFA over {0,1} that accepts binary strings whose value is divisible by 8 (binary mod 8 = 0). States 0\u20137 represent the current remainder.","      n0 = 0\n      n1 = 1\n      n2 = 2\n      n3 = 3\n      n4 = 4\n      n5 = 5\n      n6 = 6\n      n7 = 7\n      n0 = (338.0, 209.3)\n      n1 = (715.3, 212.0)\n      n2 = (432.0, 446.7)\n      n3 = (1418.7, 219.3)\n      n4 = (167.3, 640.7)\n      n5 = (585.3, 610.0)\n      n6 = (870.0, 627.3)\n      n7 = (1173.3, 622.0)\n      n0 is accepted\n      n0 to n0 = 0\n      n0 to n1 = 1\n      n1 to n3 = 1\n      n1 to n2 = 0\n      n2 to n4 = 0\n      n4 to n0 = 0\n      n4 to n1 = 1\n      n2 to n5 = 1\n      n5 to n2 = 0\n      n5 to n3 = 1\n      n3 to n6 = 0\n      n3 to n7 = 1\n      n7 to n6 = 0\n      n7 to n7 = 1\n      n6 to n4 = 0\n      n6 to n5 = 1\n      l6(1) curve = 439.5\n      l7(1) curve = 30.8\n      l8(0) curve = 16.7\n      l14(0) curve = 126.4\n      l0(0) loop angle = -1.5708\n      l13(1) loop angle = 0.4628\n      to n0\n      to n0 length = 114.5\n      to n0 angle = -0.9767, -0.2148\n    ",B.D,null,B.cO,B.CW,0.75,"boss",!1,B.H,null,B.L,"",!1)
B.QG=s(["dsl_binary_mod7","dsl_binary_mod8"],t.s)
B.Xo=new A.hK(B.QG)
B.a5r=new A.iy(7,"pdaStack")
B.a5Q=new A.dw("Beyond Finite Memory","Some languages **cannot** be recognised by a DFA or NFA. The classic example is a\u207fb\u207f \u2014 equal numbers of a's then b's.\n\nA DFA has no memory of how many a's it has seen. A **PDA** adds a **stack** \u2014 an infinite scratchpad \u2014 which solves this.",B.a5r)
B.a5R=new A.dw("PDA Transition Format",'Each PDA transition arrow has the label format:\n\n  **read, pop | push**\n\n\u2022 **read** \u2014 the input symbol consumed (**~** means consume nothing)\n\u2022 **pop**  \u2014 the stack symbol removed from the top (**~** means pop nothing)\n\u2022 **push** \u2014 the stack symbol added on top (**~** means push nothing)\n\nExample: **"a, ~ | X"** \u2014 read "a", don\'t pop, push "X".',B.bD)
B.a5E=new A.dw("Stack Strategy for a\u207fb\u207f",'Here\'s the classic approach for equal-count problems:\n\n1. **Push** a marker (e.g. X) for each "a" you read.\n2. When you start reading "b"s, **pop** one X per "b".\n3. Accept when the stack is empty and input is exhausted.\n\nIf the stack runs out before the input (or vice versa), the counts don\'t match \u2014 reject.',B.bD)
B.Q2=s([B.a5Q,B.a5R,B.a5E],t.nY)
B.Mz=new A.aL("tutorial_pda","Pushdown Automata","Learn how PDAs use a stack to recognise context-free languages.","",B.D,null,B.bd,B.Xo,0.5,"tutorial",!0,B.Q2,null,B.L,"",!1)
B.U0={'"Green Leaf"':0,"(others)":1}
B.YQ=new A.dK(B.U0,2,t.l)
B.CY=new A.c9("tutorial_pda")
B.M7=new A.aL("dsl_caterpillar_nfa","Hungry Caterpillar (NFA)",'The Very Hungry Caterpillar ends by eating EXACTLY one "Green Leaf".\nBuild an NFA over story words where .-"Green Leaf" means "every word except Green Leaf". Accept strings whose last food item is exactly one Green Leaf.','      n0 = A\n      n1 = B\n      n0 = (689.3, 458.7)\n      n1 = (1080.7, 454.7)\n      n1 is accepted\n      n0 to n1 = "Green Leaf"\n      n0 to n0 = .-"Green Leaf"\n      .-"Green Leaf" loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ',B.D,B.by,B.YQ,B.CY,0.2,"nfa",!1,B.H,null,B.L,"",!1)
B.Ul={a:0,b:1,c:2,"\u2026":3,z:4}
B.YY=new A.dK(B.Ul,5,t.l)
B.M1=new A.aL("dsl_halt_accept_y","Halt on y",'Build an FA over the lowercase English alphabet that stops computing and accepts the moment it sees the letter "y".\nUse <<Ha>> to mark a halt-and-accept state, and .-y to mean "every letter except y".',"      n0 = A\n      n1 = <<Ha>>\n      n0 = (484.0, 492.0)\n      Ha = (834.0, 492.0)\n      n0 to Ha = y\n      n0 to n0 = a,b,c,d,e,f,g,h,i,j,k,l,m,n,o,p,q,r,s,t,u,v,w,x,z\n      a,b,c,d,e,f,g,h,i,j,k,l,m,n,o,p,q,r,s,t,u,v,w,x,z loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.YY,B.CY,0.8,"fa",!1,B.H,null,B.L,"",!1)
B.U6={"(":0,")":1}
B.YV=new A.dK(B.U6,2,t.l)
B.Qe=s(["dsl_caterpillar_nfa","dsl_halt_accept_y"],t.s)
B.Xp=new A.hK(B.Qe)
B.Mn=new A.aL("pda_balanced_parens","Balanced Parentheses",'Build a PDA over {(, )} that accepts strings with balanced parentheses (e.g. "(()())" accepted, "(()" rejected).\nPush a marker on every "(" and pop it on every ")".',"      pda mode\n      n0 = A\n      n1 = B\n      n0 = (480.0, 360.0)\n      n1 = (820.0, 360.0)\n      n0 is accepted\n      n0 to n0 = (,\u2205|X\n      n0 to n1 = ),X|\u2205\n      n1 to n1 = ),X|\u2205\n      n1 to n0 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aS,null,B.YV,B.Xp,0.5,"pda",!1,B.H,null,B.L,"",!1)
B.XQ=new A.c9("pda_balanced_parens")
B.Mk=new A.aL("pda_anbn","a\u207fb\u207f","Build a PDA that accepts exactly strings of the form a\u207fb\u207f (n \u2265 1): the same number of a's followed by the same number of b's.\nClassic context-free language \u2014 not recognisable by any DFA!","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|X\n      n0 to n1 = b,X|\u2205\n      n1 to n1 = b,X|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aS,null,B.a6,B.XQ,0.5,"pda",!1,B.H,null,B.L,"",!1)
B.XP=new A.c9("pda_anbn")
B.Mm=new A.aL("pda_more_as","More a's Than b's","Build a PDA over {a, b} that accepts strings where the number of a's is strictly greater than the number of b's (in any order).\nPush for each a, pop for each b; accept if the stack is non-empty at the end.","      pda mode\n      n0 = A\n      n1 = B\n      n0 = (380.0, 360.0)\n      n1 = (720.0, 360.0)\n      n0 to n0 = a,\u2205|X\n      n0 to n0 = b,X|\u2205\n      n0 to n1 = \u2205,X|X\n      n1 is accepted\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aS,null,B.a6,B.XP,0.5,"pda",!1,B.H,null,B.L,"",!1)
B.XR=new A.c9("pda_more_as")
B.MC=new A.aL("pda_an_b2n","a\u207fb\xb2\u207f","Build a PDA that accepts strings of the form a\u207fb\xb2\u207f (n \u2265 1): for every a there must be exactly two b's.\nHint: push two markers for each a you read.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|X\n      n0 to n0 = a,\u2205|X\n      n0 to n1 = b,X|\u2205\n      n1 to n1 = b,X|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aS,null,B.a6,B.XR,0.5,"pda",!1,B.H,null,B.L,"",!1)
B.CX=new A.c9("pda_an_b2n")
B.Me=new A.aL("level_2","Level 2 \u2014 PDA Boss","Build a PDA that matches the hidden stack-based target machine. Study the transition format and think carefully about what language this could be.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = <<ha>>\n      n4 = E\n      n5 = F\n      n0 = (723.3, 204.7)\n      n1 = (1139.3, 259.3)\n      n2 = (1196.0, 527.3)\n      n3 = (739.3, 705.3)\n      n4 = (345.3, 504.7)\n      n5 = (345.3, 277.3)\n      n0 to n5 = 0,~|X\n      n0 to n1 = 1,~|Y\n      n1 to n1 = 1,~|Y\n      n1 to n2 = 0,Y|~\n      n2 to n1 = 1,\u2205|Y\n      n2 to n5 = 0,\u2205|X\n      n4 to n1 = 1,\u2205|Y\n      n4 to n5 = 0,\u2205|X\n      n5 to n4 = 1,X|~\n      n5 to n5 = 0,~|X\n      n4 to n4 = 1,X|~\n      n4 to n3 = \u2205,\u2205|~\n      n2 to n3 = \u2205,\u2205|~\n      n2 to n2 = 0,Y|~\n      l0(0,~|X) curve = -2.9\n      l3(0,Y|~) curve = 62.2\n      l4(1,\u2205|Y) curve = 55.1\n      l5(0,\u2205|X) curve = 39.9\n      l6(1,\u2205|Y) curve = 16.9\n      l7(0,\u2205|X) curve = -8.2\n      l8(1,X|~) curve = -105.4\n      l2(1,~|Y) loop angle = -0.7988\n      l9(0,~|X) loop angle = -1.5708\n      l10(1,X|~) loop angle = 1.7686\n      l13(0,Y|~) loop angle = -0.0754\n      to n0 angle = -1.0000, 0.0000\n    ",B.aS,null,B.bd,B.CX,0.25,"pda",!1,B.H,null,B.L,"",!1)
B.M_=new A.aL("pda_palindrome","PDA Palindromes","Build a PDA over {a, b} that accepts even-length palindromes (ww^R where w is any string over {a,b}).\nHint: push the first half onto the stack, then pop-match the second half.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|a\n      n0 to n0 = b,\u2205|b\n      n0 to n1 = \u2205,\u2205|\u2205\n      n1 to n1 = a,a|\u2205\n      n1 to n1 = b,b|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aS,null,B.bd,B.CX,0.75,"pda",!1,B.H,null,B.L,"",!1)
B.Ri=s(["level_2","pda_palindrome"],t.s)
B.Xs=new A.fN(B.Ri)
B.a5s=new A.iy(8,"tmTape")
B.a5z=new A.dw("The Turing Machine","A Turing machine adds a **read/write tape** to a finite automaton. The tape is infinite in both directions and starts with your input.\n\nA **read/write head** sits on one cell at a time. On each step it reads the current symbol, writes a new symbol (or leaves it), and moves **Left** or **Right** (or stays Still).",B.a5s)
B.a5y=new A.dw("TM Transition Format",'Each TM arrow label has the format:\n\n  **readSymbol writeSymbol Direction**\n\nDirection is **R** (right), **L** (left), or **S** (stay).\n\nExample: **"aXR"** \u2014 read "a", write "X", move Right.\nExample: **"\u2205\u2205S"** \u2014 read blank, write blank, stay (blank = empty cell).',B.bD)
B.a5S=new A.dw("Accepting and Rejecting","A TM **accepts** by entering an accept state (double ring) and halting.\n\nA TM **rejects** either by entering a reject state (no outgoing transition for the current symbol causes a crash) or by looping forever.\n\nThe equivalence checker uses a bounded simulation \u2014 it tests many input strings but can't always prove correctness on all inputs.",B.bD)
B.a5K=new A.dw("The Crossout Technique",'Many TM puzzles use a **crossout** strategy:\n\n1. Replace a matched symbol with **X** (or another marker) to "cross it out".\n2. Sweep the tape left/right to find the next unmatched symbol.\n3. Repeat until all symbols are matched or a mismatch is detected.\n\nYou\'ll see this in a\u207fb\u207f, a\u207fb\u207fc\u207f, palindrome, and the "ww" puzzles.',B.bD)
B.a5B=new A.dw("Multiple Loops on One State","TM states often have **many self-loops** \u2014 one for each symbol the machine should pass over without stopping.\n\nIn the canvas you can drag a self-loop's label dot to rotate it around the state circle, so diagrams stay readable even with 4\u20135 loops on one state.",B.bD)
B.R9=s([B.a5z,B.a5y,B.a5S,B.a5K,B.a5B],t.nY)
B.MI=new A.aL("tutorial_tm","Turing Machines","Learn the read/write tape model and TM transition format.","",B.D,null,B.bd,B.Xs,0.5,"tutorial",!0,B.R9,null,B.L,"",!1)
B.CZ=new A.c9("tutorial_tm")
B.Mw=new A.aL("tm_identity","TM: Accept All (Trivial)","Build the simplest possible Turing machine: one that accepts every input by halting immediately.\nA single state that is both start and accept will do it. TM transition format: readSymbol writeSymbol Direction (e.g. aBR = read a, write B, move Right).","      tm mode\n      n0 = A\n      A = (600.0, 360.0)\n      A is accepted\n      to A angle = -1.0000, 0.0000\n    ",B.aW,null,B.bd,B.CZ,0.25,"tm",!1,B.H,null,B.L,"",!1)
B.Mr=new A.aL("tm_reject_all","TM: Reject All","Build a TM that loops forever on any non-empty input (rejects by non-halt) and accepts only the empty tape.\nHint: a start state with a self-loop on every symbol that moves right will spin forever.","      tm mode\n      n0 = A\n      n1 = B\n      A = (480.0, 360.0)\n      B = (820.0, 360.0)\n      B is accepted\n      A to B = \u2205\u2205S\n      to A angle = -1.0000, 0.0000\n    ",B.aW,null,B.bd,B.CZ,0.75,"tm",!1,B.H,null,B.L,"",!1)
B.Rs=s(["tm_identity","tm_reject_all"],t.s)
B.Xq=new A.hK(B.Rs)
B.MS=new A.aL("tm_anbn","TM: a\u207fb\u207f","Build a TM that accepts exactly strings of the form a\u207fb\u207f (n \u2265 1). Classic TM exercise: repeatedly cross off one a and one b until both sides are exhausted.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      A = (260.0, 200.0)\n      B = (660.0, 200.0)\n      C = (1060.0, 200.0)\n      D = (660.0, 560.0)\n      E = (260.0, 560.0)\n      E is accepted\n      A to B = aXR\n      B to B = aXR\n      B to C = bXL\n      C to D = XXL\n      D to D = aXL\n      D to A = XXR\n      A to E = \u2205\u2205S\n      l1(aXR) loop angle = -1.5708\n      l3(XXL) loop angle = -1.5708\n      l4(aXL) loop angle = 1.5708\n      aXR curve = 80.0\n      bXL curve = 80.0\n      XXR curve = 80.0\n      to A angle = -1.0000, 0.0000\n    ",B.aW,null,B.bd,B.Xq,0.5,"tm",!1,B.H,null,B.L,"",!1)
B.XS=new A.c9("tm_anbn")
B.My=new A.aL("tm_anbncn","TM: a\u207fb\u207fc\u207f","Build a TM that accepts strings of the form a\u207fb\u207fc\u207f (n \u2265 1).\nThis language is not context-free \u2014 no PDA can recognise it \u2014 but a TM can! Cross off one a, one b, and one c per pass.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 200.0)\n      B = (580.0, 200.0)\n      C = (900.0, 200.0)\n      D = (900.0, 540.0)\n      E = (580.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      B to B = aaR\n      B to B = XXR\n      B to C = bXR\n      C to C = bbR\n      C to C = XXR\n      C to D = cXL\n      D to D = bbL\n      D to D = ccL\n      D to D = XXL\n      D to E = aaL\n      E to E = aaL\n      E to E = bbL\n      E to E = ccL\n      E to E = XXL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(XXR) loop angle = -0.8000\n      l4(bbR) loop angle = -1.5708\n      l5(XXR) loop angle = -0.8000\n      l7(bbL) loop angle = 1.5708\n      l8(ccL) loop angle = 0.8000\n      l9(XXL) loop angle = 2.3000\n      l11(aaL) loop angle = 1.5708\n      l12(bbL) loop angle = 0.8000\n      l13(ccL) loop angle = 2.3000\n      l14(XXL) loop angle = 3.1000\n      aXR curve = 70.0\n      bXR curve = 70.0\n      cXL curve = 70.0\n      aaL_E curve = 60.0\n      XXR_E curve = 60.0\n      to A angle = -1.0000, 0.0000\n    ",B.aW,null,B.bd,B.XS,0.5,"tm",!1,B.H,null,B.L,"",!1)
B.XT=new A.c9("tm_anbncn")
B.M6=new A.aL("tm_ww","TM: ww (Doubled Word)",'Build a TM that accepts strings of the form ww over {a, b}: a string that consists of some word w repeated exactly twice (e.g. "abab", "aabb aabb"). This is a classic non-context-free language.',"      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 180.0)\n      B = (660.0, 180.0)\n      C = (1060.0, 180.0)\n      D = (1060.0, 540.0)\n      E = (660.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      A to C = bXR\n      B to B = aaR\n      B to B = bbR\n      B to D = bXL\n      C to C = aaR\n      C to C = bbR\n      C to E = aXL\n      D to D = aaL\n      D to D = bbL\n      D to A = XXR\n      E to E = aaL\n      E to E = bbL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(bbR) loop angle = -0.8000\n      l5(aaR) loop angle = -1.5708\n      l6(bbR) loop angle = -0.8000\n      l7(aaL) loop angle = 1.5708\n      l8(bbL) loop angle = 0.8000\n      l10(aaL) loop angle = 1.5708\n      l11(bbL) loop angle = 0.8000\n      aXR curve = 60.0\n      bXR curve = -60.0\n      bXL curve = 60.0\n      aXL curve = -60.0\n      XXR_D curve = 80.0\n      XXR_E curve = -80.0\n      to A angle = -1.0000, 0.0000\n    ",B.aW,null,B.bd,B.XT,0.5,"tm",!1,B.H,null,B.L,"",!1)
B.XV=new A.c9("tm_ww")
B.Ma=new A.aL("tm_palindrome","TM: Palindrome","Build a TM over {a, b} that accepts palindromes of any length.\nStrategy: repeatedly peel the first and last character and verify they match.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 200.0)\n      B = (640.0, 200.0)\n      C = (1020.0, 200.0)\n      D = (1020.0, 540.0)\n      E = (640.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      A to C = bXR\n      B to B = aaR\n      B to B = bbR\n      B to E = aXL\n      C to C = aaR\n      C to C = bbR\n      C to D = bXL\n      D to D = aaL\n      D to D = bbL\n      D to A = XXR\n      E to E = aaL\n      E to E = bbL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(bbR) loop angle = -0.6000\n      l5(aaR) loop angle = -1.5708\n      l6(bbR) loop angle = -0.6000\n      l8(aaL) loop angle = 1.5708\n      l9(bbL) loop angle = 0.6000\n      l11(aaL) loop angle = 1.5708\n      l12(bbL) loop angle = 0.6000\n      aXR curve = 70.0\n      bXR curve = -70.0\n      aXL curve = -70.0\n      bXL curve = 70.0\n      to A angle = -1.0000, 0.0000\n    ",B.aW,null,B.bd,B.XV,0.5,"tm",!1,B.H,null,B.L,"",!1)
B.XU=new A.c9("tm_palindrome")
B.a5A=new A.dw("What is a Regular Expression?",'A **regular expression** (regex) is a compact notation for describing a regular language \u2014 the same class of languages recognised by DFAs and NFAs.\n\nOperators used in these puzzles:\n\u2022 **a** \u2014 literal symbol "a"\n\u2022 **ab** \u2014 concatenation (a then b)\n\u2022 **a+b** \u2014 alternation / union (a OR b)\n\u2022 **a*** \u2014 Kleene star (zero or more a)\n\u2022 **(\u2026)** \u2014 grouping',B.bD)
B.a5O=new A.dw("Regex \u2194 Automaton","Every regular expression describes exactly the same set of strings as some DFA (and vice versa). This is why they are called *regular* languages.\n\nThis section has two challenge types:\n\n**Regex \u2192 DFA** \u2014 You are given a regex and must build a DFA whose language matches it exactly.\n\n**DFA \u2192 Regex** \u2014 You are shown a read-only DFA diagram and must type a regex that describes the same language.",B.bD)
B.a5G=new A.dw("Notation Reference",'The checker uses the following notation:\n\n\u2022 **~** \u2014 empty string \u03b5  (e.g. a+~ means "a or nothing")\n\u2022 **\u2205** \u2014 empty language (matches nothing)\n\u2022 **+** \u2014 alternation  (a+b means a OR b)\n\u2022 ***** \u2014 Kleene star, postfix  (a* = zero or more a)\n\u2022 Concatenation is implicit: **ab** means a then b\n\nPrecedence (high\u2192low): star \u2192 concat \u2192 union.\nUse parentheses to override: (a+b)* = any string over {a,b}.',B.bD)
B.a5F=new A.dw("Tips: Regex \u2192 DFA",'When you see a regex, ask: "what pattern must a string satisfy?"\n\n\u2022 **ab*** \u2014 any number of b\'s after exactly one a\n\u2022 **(a+b)*abb** \u2014 anything, ending in "abb"\n\u2022 **(ab)*** \u2014 alternating pairs: \u03b5, ab, abab, \u2026\n\nThink about what the machine must *remember*. Each memory unit (e.g. "last symbol seen") usually becomes a state.',B.bD)
B.a5v=new A.dw("Tips: DFA \u2192 Regex","To derive a regex from a DFA, try **state elimination**:\n\n1. Add a super-start \u2192 original start and all accept states \u2192 super-accept with \u03b5-transitions.\n2. Remove inner states one by one, merging their transitions into regex labels on the remaining edges.\n3. The final label on the super-start \u2192 super-accept edge is your regex.\n\nIn practice, pattern recognition is often faster: spot self-loops (\u2192 *), linear paths (\u2192 concat), branches (\u2192 +).",B.bD)
B.Rj=s([B.a5A,B.a5O,B.a5G,B.a5F,B.a5v],t.nY)
B.MW=new A.aL("tutorial_regex","Regular Expressions","Learn the connection between regular expressions and finite automata.","",B.D,null,B.bd,B.XU,0.5,"tutorial",!0,B.Rj,null,B.L,"",!1)
B.nB=new A.c9("tutorial_regex")
B.em=new A.Es(1,"regexToDfa")
B.MG=new A.aL("regex_to_dfa_ab_star","Regex \u2192 DFA: ab*",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    ab*\n\nMatches "a" followed by any number of b\'s: "a", "ab", "abb", "abbb", \u2026',"      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (660.0, 580.0)\n      n1 is accepted\n      n0 to n1 = a\n      n0 to n2 = b\n      n1 to n1 = b\n      n1 to n2 = a\n      n2 to n2 = a,b\n      l2(b) loop angle = -1.5708\n      l4(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.ax,B.a6,B.nB,0.2,"regex",!1,B.H,null,B.em,"ab*",!1)
B.Mi=new A.aL("regex_to_dfa_starts_a","Regex \u2192 DFA: a(a+b)*",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    a(a+b)*\n\nMatches all strings that start with "a": "a", "aa", "ab", "aba", \u2026',"      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (660.0, 580.0)\n      n1 is accepted\n      n0 to n1 = a\n      n0 to n2 = b\n      n1 to n1 = a,b\n      n2 to n2 = a,b\n      l2(a,b) loop angle = -1.5708\n      l3(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.ax,B.a6,B.nB,0.5,"regex",!1,B.H,null,B.em,"a(a+b)*",!1)
B.Mp=new A.aL("regex_to_dfa_ends_b","Regex \u2192 DFA: (a+b)*b",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    (a+b)*b\n\nMatches all strings that end with "b": "b", "ab", "bb", "aab", \u2026',u.C,B.D,B.ax,B.a6,B.nB,0.8,"regex",!1,B.H,null,B.em,"(a+b)*b",!1)
B.P1=s(["regex_to_dfa_ab_star","regex_to_dfa_starts_a","regex_to_dfa_ends_b"],t.s)
B.ny=new A.fN(B.P1)
B.MF=new A.aL("regex_to_dfa_a_or_b_star","Regex \u2192 DFA: (a+b)*","Build a DFA over {a, b} equivalent to the regular expression:\n\n    (a+b)*\n\nMatches every string over {a, b} \u2014 including the empty string \u03b5.","      n0 = q0\n      n0 = (600.0, 360.0)\n      n0 is accepted\n      n0 to n0 = a,b\n      a,b loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.ax,B.a6,B.ny,0.2,"regex",!1,B.H,null,B.em,"(a+b)*",!1)
B.ML=new A.aL("regex_to_dfa_aba","Regex \u2192 DFA: (a+b)*aba(a+b)*",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    (a+b)*aba(a+b)*\n\nMatches all strings containing "aba" as a substring.',"      n0 = q0\n      n1 = q1\n      n2 = q2\n      n3 = q3\n      n0 = (280.0, 360.0)\n      n1 = (580.0, 360.0)\n      n2 = (880.0, 360.0)\n      n3 = (1180.0, 360.0)\n      n3 is accepted\n      n0 to n1 = a\n      n0 to n0 = b\n      n1 to n1 = a\n      n1 to n2 = b\n      n2 to n3 = a\n      n3 to n3 = a,b\n      n2 to n0 = b\n      l0(b) loop angle = -1.5708\n      l2(a) loop angle = -1.5708\n      l5(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.ax,B.a6,B.ny,0.5,"regex",!1,B.H,null,B.em,"(a+b)*aba(a+b)*",!1)
B.MV=new A.aL("regex_to_dfa_even_as","Regex \u2192 DFA: b*(ab*ab*)*","Build a DFA over {a, b} equivalent to the regular expression:\n\n    b*(ab*ab*)*\n\nMatches all strings with an even number of a's (including zero a's).",u.m,B.D,B.ax,B.a6,B.ny,0.8,"regex",!1,B.H,null,B.em,"b*(ab*ab*)*",!1)
B.R8=s(["regex_to_dfa_a_or_b_star","regex_to_dfa_aba","regex_to_dfa_even_as"],t.s)
B.nz=new A.fN(B.R8)
B.d6=new A.Es(2,"dfaToRegex")
B.Mv=new A.aL("dfa_to_regex_single_a",'DFA \u2192 Regex: Accept "a"','A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts only the single-character string "a".',"      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (660.0, 580.0)\n      n1 is accepted\n      n0 to n1 = a\n      n0 to n2 = b\n      n1 to n2 = a,b\n      n2 to n2 = a,b\n      l3(a,b) loop angle = -1.5708\n      l2(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.a6,B.nz,0.2,"regex",!1,B.H,null,B.d6,"a",!1)
B.Mh=new A.aL("dfa_to_regex_ends_b","DFA \u2192 Regex: Ends with b",'A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} that end with "b".',u.C,B.D,null,B.a6,B.nz,0.5,"regex",!1,B.H,null,B.d6,"(a+b)*b",!1)
B.M8=new A.aL("dfa_to_regex_even_as","DFA \u2192 Regex: Even a's","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} with an even number of a's.",u.m,B.D,null,B.a6,B.nz,0.8,"regex",!1,B.H,null,B.d6,"b*(ab*ab*)*",!1)
B.Qs=s(["dfa_to_regex_single_a","dfa_to_regex_ends_b","dfa_to_regex_even_as"],t.s)
B.nA=new A.fN(B.Qs)
B.MJ=new A.aL("dfa_to_regex_starts_ab","DFA \u2192 Regex: Starts with ab",'A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} that start with "ab".',"      n0 = q0\n      n1 = q1\n      n2 = q2\n      n3 = dead\n      n0 = (240.0, 360.0)\n      n1 = (560.0, 360.0)\n      n2 = (880.0, 360.0)\n      n3 = (560.0, 600.0)\n      n2 is accepted\n      n0 to n1 = a\n      n0 to n3 = b\n      n1 to n2 = b\n      n1 to n3 = a\n      n2 to n2 = a,b\n      n3 to n3 = a,b\n      l4(a,b) loop angle = -1.5708\n      l5(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.a6,B.nA,0.2,"regex",!1,B.H,null,B.d6,"ab(a+b)*",!1)
B.MY=new A.aL("dfa_to_regex_no_consec_b","DFA \u2192 Regex: No Consecutive b's","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} containing no two consecutive b's.","      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (400.0, 340.0)\n      n1 = (780.0, 340.0)\n      n2 = (580.0, 580.0)\n      n0 is accepted\n      n1 is accepted\n      n0 to n1 = b\n      n0 to n0 = a\n      n1 to n0 = a\n      n1 to n2 = b\n      n2 to n2 = a,b\n      l0(a) loop angle = -1.5708\n      l4(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.a6,B.nA,0.5,"regex",!1,B.H,null,B.d6,"a*(ba+)*b?",!1)
B.Mt=new A.aL("dfa_to_regex_binary_mod2","DFA \u2192 Regex: Even 0s","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts binary strings over {0, 1} with an even number of 0s.","      n0 = even\n      n1 = odd\n      n0 = (504.7, 310.0)\n      n1 = (1030.0, 314.0)\n      n0 is accepted\n      n0 to n1 = 0\n      n1 to n0 = 0\n      n0 to n0 = 1\n      n1 to n1 = 1\n      l0(0) curve = -74.1\n      l1(0) curve = -72.7\n      l2(1) loop angle = -1.5708\n      l3(1) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.cO,B.nA,0.8,"regex",!1,B.H,null,B.d6,"1*(01*01*)*",!1)
